sequence.script:
var raw=mc.getPayloadJSON()||{}, usage=raw.tokenUsage||{};
var input=Number(usage.inputTokenCount||0), output=Number(usage.outputTokenCount||0);
var total=Number(usage.totalTokenCount||(input+output));
var profile=String(mc.getProperty("aiProfile")||"standard");
var inRate=Number(mc.getProperty(profile==="advanced"?"advancedInputRate":"standardInputRate")||0);
var outRate=Number(mc.getProperty(profile==="advanced"?"advancedOutputRate":"standardOutputRate")||0);
var cost=((input*inRate)+(output*outRate))/1000000.0;
mc.setProperty("aiInputTokens",String(input)); mc.setProperty("aiOutputTokens",String(output));
mc.setProperty("aiTotalTokens",String(total)); mc.setProperty("aiCostUsd",String(cost));
mc.setPayloadJSON({
  answer:String(raw.content||""),
  modelRoute:{profile:profile,model:profile==="advanced"?"__AI_MODEL_ADVANCED__":"__AI_MODEL_STANDARD__"},
  safeguards:{sensitiveDataMasked:String(mc.getProperty("aiMaskTypes")||"[]")!=="[]",
    maskTypes:JSON.parse(String(mc.getProperty("aiMaskTypes")||"[]")),promptInjectionBlocked:false},
  usage:{inputTokens:input,outputTokens:output,totalTokens:total},
  costAttribution:{currency:"USD",estimatedCost:Number(cost.toFixed(8)),
    partnerId:String(mc.getProperty("partnerId")),correlationId:String(mc.getProperty("correlationId")),
    pricingSource:"demo environment configuration"},
  toolExecutions:raw.toolExecutions||[],finishReason:raw.finishReason||null,
  correlationId:String(mc.getProperty("correlationId"))
});
